import React, { Component } from "react";
import "./App.css";

class Slider extends Component {
  constructor(props) {
    super(props);
    this.interval = null;
    this.state = {
      counter: 5,
    };
  }

  componentWillMount() {
    this.interval = setInterval(() => {
      if (counter <= 0) {
        clearInterval(this.interval);
        return;
      }

      this.setState({
        counter: this.state.counter - 1,
      });
    }, 1000);
  }

  render() {
    const { counter } = this.state;
    return (
      <div className="divSlider">
        <h1 className="h1Nav">hovno : {counter}</h1>
        <img
          className="programmingIMG1"
          src="https://images.unsplash.com/photo-1587620962725-abab7fe55159?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=crop&w=1631&q=80"
          alt="programmingPhoto1"
        />
        <img
          className="programmingIMG2"
          src="https://images.unsplash.com/photo-1587620962725-abab7fe55159?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=crop&w=1631&q=80"
          alt="programmingPhoto1"
        />
      </div>
    );
  }
}
